('spanish:8-2-social-media-and-online-safety:mcq:e3bdb501', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "Which word means ‘impression’?", "options": ["la impresión", "la expresión", "la impresora", "la depresión"]}'::jsonb, '{"answer": 0, "explain": "la impresión = impression. la impresora looks almost identical but is a false friend meaning ‘printer’; expresión (expression) and depresión (depression) are other look-alikes."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:mcq:b0e44926', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"El ciberacoso puede ocurrir en cualquier momento.\" data-listen></span><br>Listen. What is being said?", "options": ["Cyberbullying can happen at any moment", "Cyberbullying never happens to anyone", "Cyberbullying happened a long time ago", "Cyberbullying only happens once a year"]}'::jsonb, '{"answer": 0, "explain": "‘puede ocurrir en cualquier momento’ = can happen at any moment. The traps negate it or change it to a fixed past or annual event."}'::jsonb),
